from flask import Flask, request, jsonify
import secrets
import smtplib

app = Flask(__name__)

tokens_db = {}

@app.route('/request-password-reset', methods=['POST'])
def request_password_reset():
    data = request.get_json()
    email = data.get("email")
    if not email:
        return jsonify({"error": "Email is required"}), 400
    token = secrets.token_urlsafe(32)
    tokens_db[email] = token
    reset_link = f"https://example.com/reset?token={token}"
    # Send the reset link via email (placeholder)
    # with smtplib.SMTP('localhost') as server:
    #     server.sendmail('from@example.com', email, f"Subject:Password Reset\n\nClick this link: {reset_link}")
    return jsonify({"message": "A reset link has been sent if the email is registered."}), 200

if __name__ == '__main__':
    app.run(debug=True)